/**
 * Default grader: run vitest. Pass = exit 0. Generated by the eval
 * extractor for tasks whose success criterion is "the test passes".
 *
 * Invoked by the eval harness with the cloned worktree as cwd. Returns
 * a JSON scorecard on stdout that the harness parses.
 */
import { execFile } from 'child_process';
import { promisify } from 'util';

const execFileP = promisify(execFile);

async function main(): Promise<void> {
  const cwd = process.cwd();
  let exit: number | null = 0;
  let output = '';
  try {
    const r = await execFileP('npx', ['--no-install', 'vitest', 'run'], {
      cwd,
      timeout: 120_000,
      env: { ...process.env, CI: '1', FORCE_COLOR: '0' },
    });
    output = (r.stdout + '\n' + r.stderr).slice(-2000);
  } catch (err) {
    const e = err as NodeJS.ErrnoException & { code?: number; stdout?: string; stderr?: string };
    exit = typeof e.code === 'number' ? e.code : null;
    output = (`${e.stdout ?? ''}\n${e.stderr ?? ''}`).slice(-2000);
  }
  const passed = exit === 0;
  process.stdout.write(JSON.stringify({
    taskName: process.env.EVAL_TASK_NAME ?? 'unknown',
    checks: [{ name: 'vitest', passed, detail: passed ? 'tests passed' : output }],
    tscExit: null,
    tscErrors: -1,
    score: passed ? 1 : 0,
    scoreMax: 1,
  }, null, 2) + '\n');
  process.exit(passed ? 0 : 1);
}

main().catch((err) => {
  console.error(err);
  process.exit(2);
});
